option.value:
/* CharPalette.qss - QSS cho app CharPalette, style cho màu mè */

QWidget {
    background-color: #22223b;
    color: #f2e9e4;
    font-family: 'Segoe UI', 'Arial', sans-serif;
    font-size: 16px;
}

QTabWidget::pane {
    border: 2px solid #9a8c98;
    border-radius: 8px;
    background: #4a4e69;
}

QTabBar::tab {
    background: #9a8c98;
    color: #22223b;
    border-radius: 6px;
    padding: 8px 20px;
    margin: 2px;
    font-weight: bold;
}

QTabBar::tab:selected {
    background: #f2e9e4;
    color: #22223b;
    border: 2px solid #c9ada7;
}

QLabel {
    background: transparent;
    color: #f2e9e4;
    font-size: 22px;
    font-weight: 600;
}

QMainWindow {
    background: #22223b;
}

